/**
 * @fileoverview Uploader view — DOM construction and rendering.
 * @module module/Uploader/view
 */

import { CLS, STATUS, DROP_ICON, FILE_ICON, REMOVE_LABEL, BROWSE_LABEL, PART } from './constants.js';
import { fmtSize, readPreview } from './helpers.js';
import razyui from '../../index.js';

// ── Build DOM ───────────────────────────────────

/**
 * Build the uploader DOM structure inside a container element.
 *
 * @param {HTMLElement} container — root element to populate
 * @param {object} config — resolved configuration
 * @returns {{ fileInput: HTMLInputElement, dropArea: HTMLElement|null, listEl: HTMLElement }}
 */
export function buildUploaderDOM(container, config) {
    const $container = razyui(container);
    $container.addClass(CLS.ROOT);
    PART.ROOT.apply(container);

    // Hidden file input
    const fileInput = PART.INPUT.create({
        type: 'file',
        ...(config.accept && { accept: config.accept }),
        ...(config.multiple && { multiple: true })
    });
    $container.append(fileInput);

    let dropArea = null;

    // Drop zone or browse button
    if (config.dropZone) {
        dropArea = PART.DROP.create({
            innerHTML:
                `<span class="${CLS.DROP_ICON}">${DROP_ICON}</span>` +
                `<span class="${CLS.DROP_TEXT}">${config.placeholder}</span>`
        });
        PART.DROP_ICON.apply(dropArea.find('.' + CLS.DROP_ICON));
        PART.DROP_TEXT.apply(dropArea.find('.' + CLS.DROP_TEXT));
        $container.append(dropArea);
    } else {
        const btn = PART.BROWSE.create({
            type: 'button',
            textContent: BROWSE_LABEL
        });
        btn.addClass('btn');
        $container.append(btn);
    }

    // File list container
    const listEl = PART.LIST.create();
    $container.append(listEl);

    return { fileInput: fileInput[0], dropArea: dropArea ? dropArea[0] : null, listEl: listEl[0] };
}

// ── Render entry row ────────────────────────────

/**
 * Render a single file-entry row and append it to the list element.
 *
 * @param {object} entry — queue entry object
 * @param {object} config — resolved configuration
 * @param {HTMLElement} listEl — the list container
 */
export async function renderEntry(entry, config, listEl) {
    const row = PART.FILE.create({
        'data-id': entry.id
    });

    // Preview thumb
    if (config.preview) {
        const thumb = PART.THUMB.create();
        const src = await readPreview(entry.file);
        if (src) {
            const img = razyui.el('img', { src });
            thumb.append(img);
        } else {
            thumb.html(FILE_ICON);
        }
        row.append(thumb);
    }

    // Info
    const info = PART.INFO.create({
        innerHTML:
            `<span class="${CLS.NAME}">${entry.file.name}</span>` +
            `<span class="${CLS.SIZE}">${fmtSize(entry.file.size)}</span>`
    });
    PART.NAME.apply(info.find('.' + CLS.NAME));
    PART.SIZE.apply(info.find('.' + CLS.SIZE));
    row.append(info);

    // Progress bar
    const bar = PART.PROGRESS.create({
        innerHTML: `<div class="${CLS.PROGRESS_FILL}"></div>`
    });
    PART.PROGRESS_FILL.apply(bar.find('.' + CLS.PROGRESS_FILL));
    row.append(bar);

    // Status text
    const stat = PART.STATUS.create({
        textContent: 'Queued'
    });
    row.append(stat);

    // Remove button
    const rm = PART.REMOVE.create({
        type: 'button',
        innerHTML: REMOVE_LABEL
    });
    row.append(rm);

    razyui(listEl).append(row);
}

// ── Update entry DOM ────────────────────────────

/**
 * Update the progress bar and status text for a given entry.
 *
 * @param {object} entry — queue entry object
 * @param {HTMLElement} listEl — the list container
 */
export function updateEntryDOM(entry, listEl) {
    const $list = razyui(listEl);
    const $row = $list.find(`[data-id="${entry.id}"]`);
    if (!$row.length) return;

    const $fill = $row.find('.' + CLS.PROGRESS_FILL);
    const $stat = $row.find('.' + CLS.STATUS);

    if ($fill.length) $fill.css('width', entry.progress + '%');

    if ($stat.length) {
        if (entry.status === STATUS.UPLOADING) {
            $stat.text(entry.progress + '%');
            $row.addClass(CLS.UPLOADING);
        } else if (entry.status === STATUS.DONE) {
            $stat.text('Done');
            $row.removeClass(CLS.UPLOADING);
            $row.addClass(CLS.DONE);
        } else if (entry.status === STATUS.ERROR) {
            $stat.text('Error');
            $row.removeClass(CLS.UPLOADING);
            $row.addClass(CLS.ERROR);
        }
    }
}

// ── Remove entry DOM ────────────────────────────

/**
 * Remove the DOM row for an entry from the list.
 *
 * @param {number} entryId — entry id
 * @param {HTMLElement} listEl — the list container
 */
export function removeEntryDOM(entryId, listEl) {
    const $row = razyui(listEl).find(`[data-id="${entryId}"]`);
    if ($row.length) $row.remove();
}

// ── Destroy DOM ─────────────────────────────────

/**
 * Clean up the uploader DOM and restore the container.
 *
 * @param {HTMLElement} container — root element
 */
export function destroyDOM(container) {
    const $container = razyui(container);
    $container.removeClass(CLS.ROOT);
    $container.html('');
}
